def conv_params_pdpt(ni, no, k):
    w = conv_params(ni, no, k)
    if ni != no:
        return w
    else:
        n = no
        r = int(np.ceil(float(n)/2))
        slices = w.view(n, n, -1).permute(2, 0, 1)
        es, Vs = [], []
        for u in slices:
            #u_sym = u.triu(diagonal=1).t() + u.triu()
            u_sym = (u + u.t()).div(2)
            e, V = torch.symeig(u_sym)
            es.append(e[r:-1])
            Vs.append(V[:,r:-1])
        return {'e': torch.stack(es), 'V': torch.stack(Vs)}
